import{c as i,S as n,j as t,m as a}from"./chunks/framework.8aa1YH_s.js";const d=JSON.parse('{"title":"Chiết khấu","description":"","frontmatter":{},"headers":[],"relativePath":"admin/chiet-khau.md","filePath":"admin/chiet-khau.md","lastUpdated":0}'),c={name:"admin/chiet-khau.md"};function l(o,h,e,u,r,g){return n(),t("div",null,[...h[0]||(h[0]=[a('<h1 id="chiet-khau" tabindex="-1">Chiết khấu <a class="header-anchor" href="#chiet-khau" aria-label="Permalink to “Chiết khấu”">​</a></h1><p><strong>Đường dẫn:</strong> <code>https://lamsonedutech.vn/admin/business/dealer</code></p><p>Chiết khấu (Dealer Discount) cấu hình <strong>tỷ lệ ăn chia doanh thu</strong> với:</p><ul><li>Giáo viên cộng tác (không phải nhân viên cơ hữu).</li><li>Đại lý / cộng tác viên bán hàng.</li><li>Đối tác phân phối.</li></ul><h2 id="khai-niem" tabindex="-1">Khái niệm <a class="header-anchor" href="#khai-niem" aria-label="Permalink to “Khái niệm”">​</a></h2><p>Khi một hóa đơn được tạo có liên quan tới một <strong>Đại lý / Giáo viên cộng tác</strong>, hệ thống tự tính chiết khấu theo công thức cấu hình.</p><p>Ví dụ:</p><ul><li>Khóa A giá 1.000.000đ.</li><li>Cấu hình chiết khấu cho giáo viên X = 40%.</li><li>Học viên mua khóa A qua link giới thiệu của giáo viên X.</li><li>Giáo viên X được tính 400.000đ chiết khấu.</li></ul><h2 id="danh-sach-chiet-khau" tabindex="-1">Danh sách chiết khấu <a class="header-anchor" href="#danh-sach-chiet-khau" aria-label="Permalink to “Danh sách chiết khấu”">​</a></h2><p>Cột chính:</p><ul><li>Tên người nhận chiết khấu (giáo viên / đại lý)</li><li>Khóa / khung chương trình áp dụng</li><li>Tỷ lệ (% hoặc số tiền cố định)</li><li>Điều kiện kích hoạt (nếu có): doanh số tối thiểu, mức bậc thang</li><li>Ngày bắt đầu - kết thúc</li><li>Trạng thái</li></ul><h2 id="tao-cau-hinh-chiet-khau" tabindex="-1">Tạo cấu hình chiết khấu <a class="header-anchor" href="#tao-cau-hinh-chiet-khau" aria-label="Permalink to “Tạo cấu hình chiết khấu”">​</a></h2><ol><li>Bấm <strong>Thêm chiết khấu</strong>.</li><li><strong>Người nhận</strong>: <ul><li>Chọn <strong>Giáo viên</strong> từ danh sách, hoặc</li><li>Chọn <strong>Đại lý</strong> từ <a href="./dai-ly">Đại lý</a>.</li></ul></li><li><strong>Phạm vi</strong>: <ul><li>Tất cả khóa của giáo viên đó (đối với giáo viên).</li><li>Khóa / Khung chương trình cụ thể.</li></ul></li><li><strong>Tỷ lệ chiết khấu</strong>: <ul><li><strong>Cố định</strong>: 1 con số duy nhất (vd 30%).</li><li><strong>Bậc thang</strong>: chia mức theo doanh thu (vd ≤ 10tr: 30%; &gt; 10tr: 35%).</li></ul></li><li><strong>Thời gian hiệu lực</strong>.</li><li>Lưu.</li></ol><h2 id="xem-chi-tiet-chiet-khau" tabindex="-1">Xem chi tiết chiết khấu <a class="header-anchor" href="#xem-chi-tiet-chiet-khau" aria-label="Permalink to “Xem chi tiết chiết khấu”">​</a></h2><p><code>https://lamsonedutech.vn/admin/business/detaildealer/:id</code></p><p>Trang chi tiết hiển thị:</p><ul><li>Bảng các giao dịch đã tính chiết khấu (theo ngày, hóa đơn).</li><li>Tổng doanh thu, tổng chiết khấu trong khoảng thời gian.</li><li>Đã thanh toán bao nhiêu, còn nợ bao nhiêu.</li></ul><h2 id="quy-trinh-thanh-toan-chiet-khau" tabindex="-1">Quy trình thanh toán chiết khấu <a class="header-anchor" href="#quy-trinh-thanh-toan-chiet-khau" aria-label="Permalink to “Quy trình thanh toán chiết khấu”">​</a></h2><ol><li>Cuối tháng/quý, xuất <strong>báo cáo chiết khấu</strong> theo người nhận.</li><li>Đối soát với phòng kế toán.</li><li>Thanh toán bằng chuyển khoản hoặc tiền mặt.</li><li>Trên hệ thống, đánh dấu <strong>Đã thanh toán</strong> cho các giao dịch tương ứng.</li></ol><h2 id="đai-ly" tabindex="-1">Đại lý <a class="header-anchor" href="#đai-ly" aria-label="Permalink to “Đại lý”">​</a></h2><p>Phần <a href="./dai-ly">Đại lý</a> là nơi quản lý tài khoản đại lý (đơn vị / cá nhân bán hàng giúp hệ thống), riêng biệt với chiết khấu của giáo viên.</p><h2 id="cau-hoi-thuong-gap" tabindex="-1">Câu hỏi thường gặp <a class="header-anchor" href="#cau-hoi-thuong-gap" aria-label="Permalink to “Câu hỏi thường gặp”">​</a></h2><p><strong>Một giáo viên có nhiều khóa, cần chiết khấu khác nhau?</strong> → Tạo nhiều dòng chiết khấu, mỗi dòng cho 1 khóa / nhóm khóa với tỷ lệ riêng.</p><p><strong>Học viên mua qua mã khuyến mãi - chiết khấu tính trên giá nào?</strong> → Mặc định tính trên <strong>giá thực thu</strong> (sau khuyến mãi). Có thể cấu hình tính trên giá gốc nếu cần.</p><p><strong>Giáo viên báo &quot;thiếu chiết khấu của tháng này&quot;.</strong> → Mở <a href="./chiet-khau">Chi tiết chiết khấu</a> → tab Giao dịch của giáo viên → đối chiếu hóa đơn. Có thể có hóa đơn chưa hoàn tất thanh toán.</p>',25)])])}const k=i(c,[["render",l]]);export{d as __pageData,k as default};
